from lxml import etree

def process_soap_request(xml_request, dtd_string):
    # Parse the XML request with DTD validation
    dtd = etree.DTD(dtd_string)
    parser = etree.XMLParser(dtd_validation=True)
    
    try:
        root = etree.fromstring(xml_request, parser)
        
        # Validate with DTD
        if not dtd.validate(root):
            raise ValueError("DTD validation failed")
        
        # Find the SOAP Envelope and Body
        envelope = root.find('{http://schemas.xmlsoap.org/soap/envelope/}Envelope')
        if envelope is None:
            raise ValueError("SOAP Envelope not found")
        
        body = envelope.find('{http://schemas.xmlsoap.org/soap/envelope/}Body')
        if body is None:
            raise ValueError("SOAP Body not found")
        
        # Extract and return contents of the body
        return etree.tostring(body, pretty_print=True, encoding='unicode')
    
    except etree.XMLSyntaxError as e:
        raise ValueError(f"XML Syntax Error: {e}")

